'use strict';

const { ChildProcessWorker } = require('./workers/ChildProcessWorker');

// jest-worker-shaped farm: run one call on a forked worker, then end() it the way
// jest-worker's BaseWorkerPool.end() does (an END message, then a delayed forceExit).
async function runTask(input) {
  const worker = new ChildProcessWorker();
  const result = await worker.call(input);
  await worker.end();
  return result;
}

module.exports = { runTask };
